@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false

note "Robustness – Rob\nUse Case – UC" as N1

class UC_node

class Robustness_dia {
  uc_node: UC_node
  nodes: List<Rob_node>
  edges: List<Rob_edge>
  --
  addNode()
  addEdge()
}

class Rob_node {
  name: String
  edges: List<Rob_edge>
}

class Rob_edge {
  name: String
  begin: Rob_node
  end: Rob_node
}

class Rob_actor
class Rob_boundary {
  layout: Layout
  is_error: bool
}
class Rob_control
class Rob_entity {
  format: Format
}

UC_node o-- Robustness_dia

Robustness_dia o-- Rob_node
Robustness_dia o-- Rob_edge

Rob_node o-- Rob_edge

Rob_actor -|> Rob_node
Rob_boundary -|> Rob_node
Rob_control -|> Rob_node
Rob_entity -|> Rob_node
@enduml
